choose.when:

 and (tpi.out_teacher ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}
 or exists (
     select 1 from td_plan_employee tpe join pm_employee pe on tpe.employee_id = pe.id
       and pe.enabled_flag = 1 and tpe.enabled_flag = 1
        and tpe.plan_implement_id = tpi.id and tpe.type = 'teacher' and
        pe.name ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}
        )
or tp.teacher ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}
 )


and (
tpi.out_emp ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}
or exists (
      select 1 from td_plan_employee tpe join pm_employee pe on tpe.employee_id = pe.id
      and pe.enabled_flag = 1 and tpe.enabled_flag = 1
       and tpe.plan_implement_id = tpi.id and tpe.type = 'employee' and
       pe.name ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}
    )
  or tp.employee_describes ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}
)


and
  (select count(1) from td_plan_employee tpe where tpe.plan_implement_id = tpi.id and tpe.enabled_flag = 1 and tpe.type = 'employee')
 ${criteria.symbol} #{criteria.value,jdbcType=INTEGER}


and (
    tpi.out_teacher  ${item.symbol} #{item.colValue, jdbcType = VARCHAR}
    or exists (
        select 1 from td_plan_employee tpe join pm_employee pe on tpe.employee_id = pe.id
        and pe.enabled_flag = 1 and tpe.enabled_flag = 1
        and tpe.plan_implement_id = tpi.id and tpe.type = 'teacher' and
        pe.name ${item.symbol} #{item.colValue, jdbcType = VARCHAR}
    )
    or tp.teacher ${item.symbol} #{item.colValue, jdbcType = VARCHAR}
)


and (
     tpi.out_emp ${item.symbol} #{item.colValue, jdbcType = VARCHAR}
     or exists (
        select 1 from td_plan_employee tpe join pm_employee pe on tpe.employee_id = pe.id
        and pe.enabled_flag = 1 and tpe.enabled_flag = 1
        and tpe.plan_implement_id = tpi.id and tpe.type = 'employee' and
        pe.name ${item.symbol} #{item.colValue, jdbcType = VARCHAR}
     )
    or tp.employee_describes ${item.symbol} #{item.colValue, jdbcType = VARCHAR}
)

mapper.select:

				select convert(int, isnull((select top 1 right(training_no, 3)   from td_plan where training_method = #{trainingMethod, jdbcType = VARCHAR}
                   and year(create_time) = year(getdate()) and enabled_flag = 1 and safety_training_flag = 0
                   order by id desc), 1))

mapper.update:

update td_plan
 set  update_time         = #{updateTime,jdbcType=TIMESTAMP},
       update_by           = #{updateBy,jdbcType=BIGINT}


    ,training_name       = #{trainingName,jdbcType=VARCHAR}


,training_method     = #{trainingMethod,jdbcType=VARCHAR}


,training_content    = #{trainingContent,jdbcType=VARCHAR}


,training_purpose    = #{trainingPurpose,jdbcType=VARCHAR}


,training_level      = #{trainingLevel,jdbcType=VARCHAR}


,profession_classify = #{professionClassify,jdbcType=VARCHAR}


,dependence_dept     = #{dependenceDept,jdbcType=VARCHAR}


,host_dept           = #{hostDept,jdbcType=VARCHAR}


,teacher             = #{teacher,jdbcType=VARCHAR}


,employee_describes  = #{employeeDescribes,jdbcType=VARCHAR}


,plan_date           = #{planDate,jdbcType=VARCHAR}


,employee_quantity   = #{employeeQuantity,jdbcType=INTEGER}


,plan_money          = #{planMoney,jdbcType=DECIMAL}


,online_flag         = #{onlineFlag,jdbcType=BIT}


,remark              = #{remark,jdbcType=VARCHAR}


,enabled_flag        = #{enabledFlag,jdbcType=BIT}


,plan_status         = #{planStatus,jdbcType=VARCHAR}


,plan_type           = #{planType, jdbcType=VARCHAR}


,dept_charge_id      = #{deptChargeId, jdbcType= BIGINT}


,plan_charge_id      = #{planChargeId, jdbcType = BIGINT}


,show_flag      = #{showFlag, jdbcType = BIT}


, change_describes          = #{changeDescribes, jdbcType=VARCHAR}


,attribute1           = #{attribute1, jdbcType=VARCHAR}


,change_oa_order           = #{changeOaOrder, jdbcType=VARCHAR}


,change_current_node           = #{changeCurrentNode, jdbcType=VARCHAR}


,change_current_person           = #{changeCurrentPerson, jdbcType=VARCHAR}


,change_plan_date          = #{changePlanDate, jdbcType=VARCHAR}


,host_dept_id          = #{hostDeptId, jdbcType=BIGINT}


,training_no          = #{trainingNo, jdbcType=VARCHAR}


 where id = #{id,jdbcType=BIGINT}


update td_plan set show_flag = 1,plan_status = '实施审批通过',
update_time =  getdate()
where id = #{id, jdbcType = BIGINT}
